   357	/// 结算最近一个前台可观测区间的真实时长，并累计到 a/v。
   358	- (void)accumulateElapsedUsageAtTime:(CFAbsoluteTime)now {
   359	    if (self.lastUsageRecordTime <= 0) {
   360	        self.lastUsageRecordTime = now;
   361	        return;
   362	    }
   363	    // 后台区间会在回前台或终止时统一补算，这里直接跳过，避免重复累计。
   364	    if ([WBEventManager hasBackgroundEnterTime]) {
   365	        self.lastUsageRecordTime = now;
   366	        return;
   367	    }
   368	    CFAbsoluteTime elapsed = now - self.lastUsageRecordTime;
   369	    if (elapsed <= 0) {
   370	        self.lastUsageRecordTime = now;
   371	        return;
   372	    }
   373	    self.appUsedTimeInSecond += elapsed;
   374	    NSInteger currentVappId = [self currentRunningVappId];
   375	    if (currentVappId > 0) {
   376	        [self mergePendingVappId:currentVappId];
   377	        self.vappUsedTimeInSecond += elapsed;
   378	    }
   379	    self.lastUsageRecordTime = now;
   380	}
