   382	/// 用进入后台和恢复时的时间点，补算挂起期间的真实时长，并并入下一次 heartbeat。
   383	- (void)applyBackgroundUsageAtTime:(CFAbsoluteTime)now {
   384	    if (![WBEventManager hasBackgroundEnterTime]) {
   385	        self.lastUsageRecordTime = now;
   386	        return;
   387	    }
   388	    // 根据生命周期时间点重建后台挂起区间，并将其并入下一次 heartbeat。
   389	    CFAbsoluteTime backgroundTime = [WBEventManager backgroundEnterTime];
   390	    if (backgroundTime > 0 && now >= backgroundTime) {
   391	        NSTimeInterval backgroundDuration = now - backgroundTime;
   392	        self.appUsedTimeInSecond += backgroundDuration;
   393	        self.backgroundUsedTimeInSecond += backgroundDuration;
   394	        // 只有进入后台时确实有 vapp 在跑，才把后台区间同时累计进 v。
   395	        if ([WBEventManager backgroundHadRunningVapp]) {
   396	            NSInteger backgroundVappId = [WBEventManager backgroundVappId];
   397	            [self mergePendingVappId:backgroundVappId];
   398	            self.vappUsedTimeInSecond += backgroundDuration;
   399	        }
   400	    }
   401	    [WBEventManager clearBackgroundTrackingState];
   402	    self.lastUsageRecordTime = now;
   403	}
